// Deep Link Route Model
class DeepLinkRoute {
  final String path;
  final Map<String, String> parameters;
  final Map<String, String> queryParameters;

  DeepLinkRoute({
    required this.path,
    this.parameters = const {},
    this.queryParameters = const {},
  });

  @override
  String toString() =>
      'DeepLinkRoute(path: $path, params: $parameters, query: $queryParameters)';
}

// Deep Link Parser
class DeepLinkParser {
  static const String scheme = 'myapp';

  static DeepLinkRoute? parse(String? uriString) {
    if (uriString == null || uriString.isEmpty) return null;

    try {
      final uri = Uri.parse(uriString);

      if (uri.scheme != scheme) return null;

      final pathSegments = uri.pathSegments;
      final host = uri.host;

      // Combine host and path segments to form the full path
      final fullSegments = <String>[if (host.isNotEmpty) host, ...pathSegments];

      final path = '/${fullSegments.join('/')}';
      final parameters = _extractPathParameters(fullSegments);
      final queryParameters = uri.queryParameters;

      return DeepLinkRoute(
        path: path,
        parameters: parameters,
        queryParameters: queryParameters,
      );
    } catch (e) {
      debugPrint('Error parsing deep link: $e');
      return null;
    }
  }

  static Map<String, String> _extractPathParameters(List<String> segments) {
    final params = <String, String>{};

    // Pattern: myapp://profile/123 -> {section: profile, id: 123}
    if (segments.isNotEmpty) {
      params['section'] = segments[0];
    }
    if (segments.length > 1) {
      // Check if second segment looks like an ID
      params['id'] = segments[1];
    }
    if (segments.length > 2) {
      params['action'] = segments[2];
    }

    return params;
  }
}

// Deep Link Handler Singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();

  factory DeepLinkHandler() => _instance;

  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  String? _initialLink;
  bool _isInitialized = false;

  final StreamController<DeepLinkRoute> _deepLinkController =
      StreamController<DeepLinkRoute>.broadcast();

  Stream<DeepLinkRoute> get deepLinkStream => _deepLinkController.stream;

  Future<void> initialize() async {
    if (_isInitialized) return;
    _isInitialized = true;

    // Handle initial link (app was opened via deep link)
    try {
      _initialLink = await getInitialLink();
      if (_initialLink != null) {
        debugPrint('Initial deep link: $_initialLink');
        _handleDeepLink(_initialLink!);
      }
    } catch (e) {
      debugPrint('Error getting initial link: $e');
    }

    // Handle incoming links while app is running
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          debugPrint('Incoming deep link: $link');
          _handleDeepLink(link);
        }
      },
      onError: (Object err) {
        debugPrint('Error receiving deep link: $err');
      },
    );
  }

  void _handleDeepLink(String link) {
    final route = DeepLinkParser.parse(link);
    if (route != null) {
      debugPrint('Parsed route: $route');
      _deepLinkController.add(route);
      _navigateToRoute(route);
    }
  }

  void _navigateToRoute(DeepLinkRoute route) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not ready, queuing route: $route');
      // Retry after a short delay
      Future.delayed(const Duration(milliseconds: 500), () {
        _navigateToRoute(route);
      });
      return;
    }

    final section = route.parameters['section'] ?? '';

    switch (section) {
      case 'profile':
        final profileId = route.parameters['id'] ?? '';
        final source =
            route.queryParameters['source'] ?? 'direct';
        navigator.pushNamed(
          '/profile',
          arguments: ProfileArguments(
            profileId: profileId,
            source: source,
          ),
        );
        break;

      case 'payment':
        final action = route.parameters['id'] ?? '';
        final transactionId =
            route.queryParameters['transaction_id'] ?? '';
        final amount = route.queryParameters['amount'] ?? '';
        navigator.pushNamed(
          '/payment/$action',
          arguments: PaymentArguments(
            action: action,
            transactionId: transactionId,
            amount: amount,
          ),
        );
        break;

      case 'campaign':
        final campaignId = route.parameters['id'] ?? '';
        final utm_source = route.queryParameters['utm_source'] ?? '';
        final utm_medium = route.queryParameters['utm_medium'] ?? '';
        navigator.pushNamed(
          '/campaign',
          arguments: CampaignArguments(
            campaignId: campaignId,
            utmSource: utm_source,
            utmMedium: utm_medium,
          ),
        );
        break;

      case 'notification':
        final notificationType = route.parameters['id'] ?? '';
        final messageId =
            route.queryParameters['message_id'] ?? '';
        navigator.pushNamed(
          '/notification',
          arguments: NotificationArguments(
            type: notificationType,
            messageId: messageId,
          ),
        );
        break;

      case 'product':
        final productId = route.parameters['id'] ?? '';
        final referrer = route.queryParameters['ref'] ?? '';
        navigator.pushNamed(
          '/product',
          arguments: ProductArguments(
            productId: productId,
            referrer: referrer,
          ),
        );
        break;

      default:
        debugPrint('Unknown deep link section: $section');
        navigator.pushNamed('/not-found', arguments: route.path);
        break;
    }
  }

  void dispose() {
    _linkSubscription?.cancel();
    _deepLinkController.close();
    _isInitialized = false;
  }
}

