// App Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case '/':
        return MaterialPageRoute(builder: (_) => const HomeScreen());

      case '/profile':
        final args = settings.arguments as ProfileArguments?;
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(
            profileId: args?.profileId ?? 'unknown',
            source: args?.source ?? 'direct',
          ),
        );

      case '/payment/confirm':
        final args = settings.arguments as PaymentArguments?;
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            transactionId: args?.transactionId ?? '',
            amount: args?.amount ?? '',
          ),
        );

      case '/payment/status':
        final args = settings.arguments as PaymentArguments?;
        return MaterialPageRoute(
          builder: (_) => PaymentStatusScreen(
            transactionId: args?.transactionId ?? '',
          ),
        );

      case '/campaign':
        final args = settings.arguments as CampaignArguments?;
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(
            campaignId: args?.campaignId ?? '',
            utmSource: args?.utmSource ?? '',
            utmMedium: args?.utmMedium ?? '',
          ),
        );

      case '/notification':
        final args = settings.arguments as NotificationArguments?;
        return MaterialPageRoute(
          builder: (_) => NotificationScreen(
            type: args?.type ?? '',
            messageId: args?.messageId ?? '',
          ),
        );

      case '/product':
        final args = settings.arguments as ProductArguments?;
        return MaterialPageRoute(
          builder: (_) => ProductScreen(
            productId: args?.productId ?? '',
            referrer: args?.referrer ?? '',
          ),
        );

      case '/not-found':
        final path = settings.arguments as String? ?? 'unknown';
        return MaterialPageRoute(
          builder: (_) => NotFoundScreen(path: path),
        );

      default:
        return MaterialPageRoute(
          builder: (_) => NotFoundScreen(path: settings.name ?? 'unknown'),
        );
    }
  }
}

// Wrapper widget that initializes deep link handler
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();
  StreamSubscription<DeepLinkRoute>? _routeSubscription;
  final List<String> _linkLog = [];

  @override
  void initState() {
    super.initState();
    _initDeepLinks();
  }

  Future<void> _initDeepLinks() async {
    await _deepLinkHandler.initialize();
    _routeSubscription = _deepLinkHandler.deepLinkStream.listen((route) {
      setState(() {
        _linkLog.add(
            '${DateTime.now().toIso8601String()}: ${route.path} (params: ${route.parameters}, query: ${route.queryParameters})');
      });
    });
  }

  @override
  void dispose() {
    _routeSubscription?.cancel();
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return HomeScreen(linkLog: _linkLog);
  }
}

